window.__LIBQ=window.__LIBQ||{};window.__LIBQ["the-gioi-hoan-my"]=window.__LIBQ["the-gioi-hoan-my"]||{};window.__LIBQ["the-gioi-hoan-my"]["q03"]=window.__LIBQ["the-gioi-hoan-my"]["q03"]||{};window.__LIBQ["the-gioi-hoan-my"]["q03"]["techniques"]={"updatedAt":"2026-07-20","count":122,"techniques":[{"id":"luyen-hoa-huyet-nhuc-than-dich","name":"Luyện hóa huyết nhục thành thần dịch","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Liễu Thần","soHuu":["Liễu Thần"],"blurb":"Thần năng của Liễu Thần dùng cành liễu xán lạn cắm vào khối huyết nhục sinh linh thuần huyết, cô đặc gần như tức thời thành giọt thần dịch tinh hoa căn bản.","detail":"Liễu Thần cắm cành liễu tỏa hào quang xanh biếc vào các khối huyết nhục sinh linh thuần huyết mấy ngàn cân, gần như tức thời áp súc chúng thành các giọt thần dịch tinh hoa cô đặc. Từ huyết nhục Thôn Thiên Tước luyện ra giọt mặc ngọc, huyết Cùng Kỳ ra giọt đỏ, sinh linh Nam Vẫn Thần Sơn và Nghi Sơn ra giọt vàng và giọt trắng tinh — tổng cộng bốn giọt thần dịch quý hơn hơn mười con thái cổ di chủng.","nguon":["@c0202"]},{"id":"bao-thuat-mao-cau","name":"Bảo thuật của Mao Cầu","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Nhóc Tỳ","Mao Cầu"],"blurb":"Bảo thuật biến hóa cho phép thay đổi dung mạo và chiều cao. Nhóc Tỳ dùng để cải trang, biến thành dáng giống một cây gậy trúc khác hẳn ngày thường.","detail":"Bảo thuật biến hóa vốn của Mao Cầu, Nhóc Tỳ sử dụng để đổi dung mạo và kéo dài chiều cao thành dáng giống cây gậy trúc, tạo khác biệt lớn so với bộ dạng cũ nhằm che giấu thân phận khi tung tin đồn thăm dò ở Sơ Thủy Địa.","nguon":["@c0203"]},{"id":"than-con-bao-thuat","name":"Thần Côn","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Bằng tộc","soHuu":["Nhóc Tỳ"],"blurb":"Bí mật bất truyền của Bằng tộc; chiêu “xuống biển thành Côn” tạo đại dương với con cá lớn màu đen quật đuôi hóa phù văn đen đánh bay chúng nhân.","detail":"Thần Côn là một trong những bảo thuật thuộc bí mật bất truyền của Bằng tộc, gắn với thân phận Côn Bằng của Nhóc Tỳ. Khi thi triển, sau lưng nó mọc đôi cánh Côn Bằng dùng để bay lượn và đánh nổ bảo cụ của địch. Chiêu thức tiêu biểu là “xuống biển thành Côn”: nó tạo ra cả một vùng đại dương mênh mông với một con cá lớn màu đen bơi trong đó, con cá quật đuôi hóa thành phù văn đen đánh bay đám đông. Trong trận ở Sơ Thủy Địa, Nhóc Tỳ dùng Thần Côn để trói và đạp Tứ công tử Thác Bạt Tộc ngã xuống đất, sau đó giậm chân giết chết hắn tại chỗ. Cuối cùng nó còn kết hợp bảo thuật Côn Bằng với lôi điện để truy sát nhân mã của hơn mười tộc, đại khai sát giới.","nguon":["@c0205"]},{"id":"sat-tran-giao-long-vu-toc","name":"Sát trận Giao Long","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Sát trận trấn giáo","hePhai":"Vũ Tộc","soHuu":["Vũ Tộc"],"blurb":"Đại trận trấn giáo của Vũ Tộc, dùng mười mấy khối nguyên thủy bảo cốt xương Giao kết hợp triệu Hôi Giao vây hãm thiên địa.","detail":"Sát trận trấn giáo của Vũ Tộc bày ra để đối phó Nhóc Tỳ. Trận dùng mười mấy khối nguyên thủy bảo cốt, mỗi khối là một di chủng Thái Cổ và đều là xương Giao, kết hợp thành đại trận Giao Long phun mưa ánh sáng nghiền ép vây hãm thiên địa, mạnh đủ áp chế cả hung thú thần huyết. Cuối cùng bị con Toan Nghê tím của Nhóc Tỳ nuốt Hôi Giao và phá vỡ.","nguon":["@c0206"]},{"id":"dai-sat-tran-vu-toc","name":"Đại sát trận Vũ Tộc","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Chưa rõ","hePhai":"Vũ Tộc","soHuu":["Vũ Tộc"],"blurb":"Trận pháp Vũ Tộc bày ra nhằm diệt cả hư thân lẫn chân thân của Hùng Hài Tử khi nó tiến công.","detail":"Khi Nhóc Tỳ mở màn trận đấu tại khu động thiên phúc địa, Vũ Tộc bố trí đại sát trận với mục tiêu tiêu diệt cả hư thân lẫn chân thân của Hùng Hài Tử cùng lúc, đề phòng đối thủ chỉ hiện diện bằng phân thân.","nguon":["@c0209"]},{"id":"thuy-mac-gia-thien","name":"Thủy Mặc Già Thiên","cn":"","loai":"than-thong","loaiLabel":"Thần thông phòng ngự","phamCap":"Không rõ","hePhai":"Vũ Tộc","soHuu":[],"blurb":"Thần thông phòng ngự của Vũ Tộc, tạo lồng ánh sáng xanh lam như thủy tinh để chắn công kích.","detail":"Một ông già Vũ Tộc quát tên thần thông này, dựng lên lồng ánh sáng xanh lam như thủy tinh nhằm chặn đứng linh vũ màu vàng của bảo thuật Côn Bằng do Nhóc Tỳ phóng ra trong trận chiến ở tịnh thổ Hư Thần Giới.","nguon":["@c0210"]},{"id":"than-tran-nguyen-thuy-tran-toc-vu-toc","name":"Thần trận nguyên thủy trấn tộc Vũ Tộc","cn":"","loai":"khac","loaiLabel":"Trận pháp trấn tộc","phamCap":"Không rõ","hePhai":"Vũ Tộc","soHuu":[],"aliases":["Sát trận vô lượng"],"blurb":"Đại trận sát của Vũ Tộc bày trong tịnh thổ, có thần trận nguyên thủy ở trung tâm dùng để phản kích.","detail":"Vũ Tộc bày sát trận vô lượng phủ sương mù phù văn trong tịnh thổ Hư Thần Giới; khi Nhóc Tỳ dùng chín tòa Động Thiên tấn công, tộc kích hoạt thần trận nguyên thủy trấn tộc ở trung tâm để phản kích, quyết chỉ được thắng không được bại.","nguon":["@c0210"]},{"id":"dong-thien-than-thong","name":"Động Thiên","loai":"than-thong","loaiLabel":"Thần thông thân thể","phamCap":"Cực phẩm","hePhai":"","soHuu":["Nhóc Tỳ"],"blurb":"Năng lực mở nhiều tòa “Động Thiên” — miệng núi lửa tuôn dung nham và tinh hoa thiên địa để bổ sung tinh khí thần cho bản thân.","detail":"Nhóc Tỳ có thể mở ra các tòa Động Thiên như miệng núi lửa, dung nham cuồn cuộn tuôn ra cung cấp tinh khí thần liên tục trong chiến đấu. Trong trận với pháp chỉ Thần Linh, nó tăng dần từ năm tòa lên tòa thứ bảy rồi mở tới chín tòa. Quần hùng chấn kinh vì với Nhân Tộc, việc mở chín tòa Động Thiên chỉ ghi trong sách cổ, gần bằng dòng dõi Thần Linh còn sót lại, khiến nhiều người nghi ngờ Nhóc Tỳ không phải Nhân Loại thuần túy.","nguon":["@c0211"]},{"id":"dai-tran-vu-toc","name":"Đại trận Vũ Tộc","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Đại trận thần bí","hePhai":"Vũ Tộc","soHuu":["Vũ Tộc"],"blurb":"Đại trận thần bí mạnh mẽ ở trung tâm Hư Thần Giới, triệu các di chủng Thái Cổ như chân thân để ngăn cản kẻ địch.","detail":"Trung tâm Hư Thần Giới có một đại trận thần bí; khi kích hoạt, các di chủng Thái Cổ như Giao Long, Dơi Thần, Khổng Tước xuất hiện như chân thân. Đại trận ngăn cản sự giết chóc của Nhóc Tỳ khiến nó nhất thời không cách nào tiến vào, kiếm gãy dù sắc bén cũng không công phá nổi phù văn. Về sau Vũ Tộc chủ động thu toàn bộ hào quang bảo cốt để triển khai pháp chỉ Thần Linh.","nguon":["@c0211"]},{"id":"te-vu-than","name":"Tế Vũ Thần","loai":"bi-thuat","loaiLabel":"Thần chú / Nghi thức","phamCap":"Không rõ","hePhai":"Vũ Tộc","soHuu":["Vũ Tộc"],"blurb":"Đoạn thần chú cổ xưa của Vũ Tộc dùng để triệu thỉnh và cứu viện pháp chỉ Vũ Thần.","detail":"Đám già Vũ Tộc trong vùng tịnh thổ ngồi xếp bằng ngâm tụng thần chú cổ xưa, người trẻ làm theo, khuếch tán gợn sóng thần bí như thủy triều. Nghi thức khiến pháp chỉ Vũ Thần đang suy yếu thức tỉnh mạnh hơn, hóa thành vầng mặt trời vàng óng nổi giận phun mưa mặt trời màu vàng.","nguon":["@c0212"]},{"id":"ao-nghia-vu-than","name":"Áo nghĩa của Vũ Thần","loai":"khac","loaiLabel":"Pháp tắc / Thần đạo","phamCap":"Thần đạo","hePhai":"Vũ Tộc","soHuu":["Vũ Thần"],"blurb":"Ý nghĩa thâm ảo của Vũ Thần biểu hiện thành mưa mặt trời màu vàng và lôi điện.","detail":"Pháp tắc thần đạo của Vũ Thần biểu hiện qua mưa mặt trời (dông tố) và lôi điện như dải ngân hà. Vũ Thần dựa vào cả mưa lẫn lôi điện hỗ trợ nhau mà tồn tại, khiến uy thế càng thêm mạnh mẽ khi pháp chỉ thức tỉnh.","nguon":["@c0212"]},{"id":"dai-tran-phu-van-vu-toc","name":"Đại trận phù văn tịnh thổ Vũ Tộc","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Vũ Tộc","soHuu":["Vũ Tộc"],"blurb":"Đại trận nhiều tầng của Vũ Tộc ẩn nấp trong bảo cốt tịnh thổ, phát khí Hỗn Độn và cấm trận trung tâm có sức hủy diệt diện rộng.","detail":"Đại trận phù văn nhiều tầng do Vũ Tộc chủ trì trong tịnh thổ, ẩn giấu quanh bảo cốt và phát ra khí Hỗn Độn. Nhóc Tỳ dùng kiếm gãy làm chín Động Thiên hiện ra để đối kháng phù văn, liên tiếp phá tan mười một tầng đại trận. Về sau một ông lão nham hiểm kích nổ cấm trận trung tâm, giết hơn trăm cao thủ Vũ Tộc lẫn khiến Nhóc Tỳ trọng thương gần đứt rời thân thể.","nguon":["@c0213"]},{"id":"dong-thien-thu-muoi","name":"Động Thiên thứ mười","cn":"","loai":"than-thong","loaiLabel":"Cảnh giới thần thông","phamCap":"thần thoại","hePhai":"Động Thiên cảnh","soHuu":["Nhóc Tỳ"],"blurb":"Động Thiên thứ mười là cảnh giới vượt trên chín Động Thiên, được xem là thần thoại cực khó thành. Nhóc Tỳ đang cố mở cảnh giới này trong lúc bị Vũ Tộc và các đối thủ khác vây công.","detail":"Chương 214 cho thấy tòa Động Thiên thứ mười của Nhóc Tỳ chỉ như ẩn như hiện, cần bản thân chủ động đoạt tạo hóa và đắp nặn hình thể chân thật mới có thể thành hình. Việc mở nó tiêu hao tinh khí cực lớn và khiến các thế lực đối địch kinh hoàng muốn ngăn cản.","nguon":["@c0214"]},{"id":"dai-duong-mau-den","name":"Đại dương màu đen","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật","phamCap":"mạnh","hePhai":"không rõ","soHuu":["Nhóc Tỳ"],"blurb":"Đại dương màu đen là bảo thuật mạnh của Nhóc Tỳ, do phù văn hóa thành biển đen với cá lớn màu đen. Trong trận tịnh thổ Vũ Tộc, nó được dùng để cuốn giết hàng trăm người.","detail":"Khi Nhóc Tỳ đại khai sát giới trong tịnh thổ, đại dương màu đen hiện ra sau lưng và nhấn chìm chiến trường. Bảo thuật này phối hợp với Toan Nghê tím, chia cắt và tiêu diệt đông đảo cao thủ Vũ Tộc, đồng thời ngăn họ mở đại trận cuối cùng.","nguon":["@c0214"]},{"id":"muoi-dong-thien","name":"Mười Động Thiên","cn":"","loai":"khac","loaiLabel":"Cảnh giới tu hành","phamCap":"Cực hạn cảnh giới Động Thiên","hePhai":"Động Thiên","soHuu":["Nhóc Tỳ"],"blurb":"Mười Động Thiên là cực hạn hiếm thấy của cảnh giới Động Thiên, mở đủ mười tòa Động Thiên. Con đường này cực khó, cơ hội mong manh, ngay cả hậu nhân Thần Linh cũng khó đi đến cùng.","detail":"Người thường mở bốn tòa Động Thiên đã đủ tiến thêm một đại cảnh giới, còn Nhóc Tỳ đi tới tòa thứ chín vẫn chưa kết thúc. Động Thiên thứ mười là cửa ải cấm kỵ, sách cổ Nhân Tộc lảng tránh, người có thiên phú đi đến cuối vẫn có thể thân tử đạo tiêu; Nhóc Tỳ chịu dày vò nửa tháng, cuối cùng mở thành công và khiến mười Động Thiên giao hòa như mười mặt trời.","nguon":["@c0217"]},{"id":"cuc-canh","name":"Cực Cảnh","cn":"","loai":"khac","loaiLabel":"Cảnh giới","phamCap":"Đỉnh cao cảnh giới hiện tại","hePhai":"Động Thiên","soHuu":["Nhóc Tỳ"],"blurb":"Cực Cảnh là đỉnh cao của cảnh giới Động Thiên mà Nhóc Tỳ đạt tới sau khi mở thành công Động Thiên thứ mười. Trạng thái này khiến nó khôi phục hoàn toàn và cường thịnh hơn xa trước đó.","detail":"Sau khi Động Thiên thứ mười xuất hiện, chín tòa Động Thiên còn lại xoay quanh và giao hòa, tinh khí sinh mệnh tuôn trào chữa lành thân thể Nhóc Tỳ. Khi thương thế khỏi hẳn, nó chính thức đứng ở đỉnh cao cảnh giới này, được gọi là Cực Cảnh.","nguon":["@c0217"]},{"id":"than-uy-chi-ton","name":"Thần uy Chí Tôn","cn":"","aliases":["Thần uy Chí Tôn của mười Động Thiên"],"loai":"than-thong","loaiLabel":"Thần uy","phamCap":"Gắn với mười Động Thiên","hePhai":"Động Thiên","soHuu":["Nhóc Tỳ"],"blurb":"Uy thế Chí Tôn bộc phát sau khi mở đủ mười Động Thiên, khiến linh hồn đối thủ rung động và muốn quỳ phục. Khi triển khai, quanh người hình thành phù văn vàng như thần vực, có thể phân giải bảo thuật và nghiền nát kẻ địch.","detail":"Trong cuộc vây săn ở khu rừng nguyên thủy, Nhóc Tỳ bộc phát thần uy Chí Tôn của mười Động Thiên. Phù văn màu vàng bao phủ quanh người như một vùng thần giới, bảo thuật xông vào bị phân giải, người tấn công bị nghiền nát thành tro; uy thế này được nhận ra là truyền thuyết từng do Tây Lăng Thú Sơn nhắc tới.","nguon":["@c0218"]},{"id":"diem-chi-phu-van","name":"Điểm chỉ phù văn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Phù văn","soHuu":["Nhóc Tỳ"],"blurb":"Một chỉ xuất ra kèm phù văn lấp lánh, trực tiếp làm nổ tung đối thủ. Nhóc Tỳ dùng chiêu này giết một cường giả Vũ Tộc khi bị chỉ mặt khiêu khích.","detail":"Khi một cường giả Vũ Tộc chỉ tay vào mặt, Nhóc Tỳ nói ghét nhất bị người khác chỉ vào rồi giơ tay điểm một chỉ. Phù văn sáng lên, cường giả kia lập tức nổ tung trước mặt mọi người.","nguon":["@c0218"]},{"id":"giam-giu-hu-khong-phu-van-mau-vang","name":"Giam giữ hư không","cn":"","aliases":["Giam giữ hư không bằng phù văn màu vàng"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Gắn với mười Động Thiên","hePhai":"Phù văn","soHuu":["Nhóc Tỳ"],"blurb":"Phù văn màu vàng bao phủ thập phương, khóa chặt hư không khiến cường giả xung quanh bất động như thời gian ngưng trệ. Sau đó phù văn nổ tung và nghiền nát toàn bộ địch thủ.","detail":"Ở cuối cuộc vây săn, Nhóc Tỳ tuyên bố không ai được rời đi rồi để phù văn vàng bao phủ bốn phương. Hư không bị giam giữ, mọi người không thể động đậy, kế đó phù văn bùng nổ khiến từng thân thể chia năm xẻ bảy và hóa thành tro tàn.","nguon":["@c0218"]},{"id":"nhan-quang-xuyen-pha","name":"Nhãn quang xuyên phá","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Nhóc Tỳ"],"blurb":"Thần thông công kích bằng ánh sáng vàng từ hai mắt của Nhóc Tỳ.","detail":"Trong trận bị nhóm liên minh tán tu vây ép, Nhóc Tỳ bắn hai chùm sáng vàng óng từ mắt, mang ký hiệu óng ánh, xuyên thủng ngực bốn tên đầu lĩnh và khiến đối phương kinh hãi.","nguon":["@c0219"]},{"id":"quyen-phap-thai-duong","name":"Quyền pháp thái dương","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Nhóc Tỳ"],"blurb":"Quyền pháp của Nhóc Tỳ bùng sáng như thái dương khi đối đầu Bích Lân Báo.","detail":"Nhóc Tỳ nện một quyền khiến phù văn dâng lên từ nắm đấm, ánh sáng rực như một vầng thái dương, nhấn chìm và làm nổ tung Bích Lân Báo to như tòa núi.","nguon":["@c0219"]},{"id":"phu-van-mau-vang","name":"Phù văn màu vàng","cn":"","aliases":["Ký hiệu vàng óng"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Nhóc Tỳ","soHuu":["Nhóc Tỳ"],"blurb":"Thần thông phù văn màu vàng của Nhóc Tỳ, bùng lên như sóng biển bao phủ núi sông. Ký hiệu này có thể giam cầm, nghiền nổ địch thủ và chấn Ly Long phun máu.","detail":"Trong trận quét ngang chư giáo, Nhóc Tỳ dùng phù văn màu vàng bao phủ chiến trường, khiến nhiều người trên không và dưới đất nổ tung. Thần thông này cũng được dùng để giam cầm các di chủng Thái Cổ đang bay trốn và là đòn đầu tiên làm Ly Long thổ huyết.","nguon":["@c0220"]},{"id":"toan-nghe-bao-thuat","name":"Toan Nghê bảo thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bảo thuật thái cổ di chủng","hePhai":"","soHuu":["Nhóc Tỳ"],"blurb":"Bảo thuật được Nhóc Tỳ thi triển khi giao chiến với lão già Thái Cổ Thần Sơn.","detail":"Khi tế xuất, phong lôi nổi dậy, phù văn màu vàng kim ngập trời bao phủ, giúp Nhóc Tỳ đánh bay lão già dù đối phương có bảo vật hộ thân.","nguon":["@c0222"]},{"id":"co-phap-thien-loi","name":"Cổ pháp thiên lôi","cn":"","loai":"cong-phap","loaiLabel":"Cổ pháp","phamCap":"không rõ, bản không đầy đủ","hePhai":"Thái Cổ Thần Sơn","soHuu":["Nhóc Tỳ"],"blurb":"Một bộ cổ pháp huyền ảo khó lường mà Nhóc Tỳ lấy được khi chuộc Ly Long. Khi thi triển có tia sét ngập trời, nhưng pháp này không đầy đủ và không hoàn chỉnh.","detail":"Nhóc Tỳ giữ Ly Long lại để mặc cả, buộc hai Hoàng Kim Thú của Thái Cổ Thần Sơn đồng ý chuộc thiếu chủ. Kết quả Nhóc Tỳ lấy được một bộ cổ pháp thiên lôi, uy thế kinh khủng khi triển khai nhưng chỉ là bản không hoàn chỉnh.","nguon":["@c0223"]},{"id":"dung-hop-tinh-than-voi-muoi-dong-thien-thanh-tien-vuc","name":"Dung hợp tinh thần với mười Động Thiên thành tiên vực","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cực cảnh Động Thiên cảnh","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Mốc phá cực hạn khi tinh thần của Thạch Hạo dung hợp với mười Động Thiên, hóa thành một tiên vực.","detail":"Trong lần Cực Cảnh Tẩy Lễ, tinh khí thần của Thạch Hạo cô đọng thành tia sáng bay vào miệng mười Động Thiên. Sau khoảnh khắc trời đất như lắng xuống, tinh thần cùng mười Động Thiên dung hợp thành một tiên vực, mở ra hướng biến hóa mới cho cực cảnh Động Thiên.","nguon":["@c0224"]},{"id":"dao-chieu-nhac-bong-thac-nuoc-bang-phu-van","name":"Đảo chiều nhấc bổng thác nước bằng phù văn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Cách vận dụng phù văn trong luyện thể khiến thác nước ngừng lại rồi chảy ngược lên trời.","detail":"Trong quá trình tự tôi luyện trước tẩy lễ, Thạch Hạo dùng phù văn màu vàng bao bọc thân thể, gầm lên làm thác nước ngừng trong giây lát rồi đảo chiều chảy ngược. Đây là một biểu hiện thần lực và năng lực khống chế phù văn khi hắn rèn cực hạn thân thể, phù văn và tinh thần.","nguon":["@c0224"]},{"id":"dien-bien-lai-dong-thien","name":"Diễn biến lại Động Thiên","aliases":["Tái Diễn","Sáng tạo vạn vật"],"cn":"","loai":"than-thong","loaiLabel":"Thần thông tu luyện","phamCap":"Chạm tới áo nghĩa đại đạo trong Động Thiên cảnh","hePhai":"Đường tu luyện riêng của Nhóc Tỳ","soHuu":["Nhóc Tỳ"],"blurb":"Thủ pháp dồn tinh khí thần vào một Động Thiên để tái tạo hình thái, sinh cơ và cỏ cây, nhằm mở rộng Động Thiên tới tầng mức cao hơn.","detail":"Nhóc Tỳ dùng chín Động Thiên cùng chất lỏng của Liễu thần để thử diễn biến lại một Động Thiên, tạo sinh cơ và hình thái như miệng núi lửa. Lần đầu chỉ có hiệu quả bước đầu rồi các điểm sáng nổ tung, cho thấy việc sáng tạo sinh mệnh và mở rộng Động Thiên đã chạm tới giới hạn cảnh giới.","nguon":["@c0225"]},{"id":"tu-huy-roi-tai-tao-dong-thien","name":"Tự hủy rồi tái tạo Động Thiên","aliases":[],"cn":"","loai":"bi-thuat","loaiLabel":"Thủ pháp đột phá cấm kỵ","phamCap":"Cấm kỵ trong Động Thiên cảnh","hePhai":"Đường tu luyện riêng của Nhóc Tỳ","soHuu":["Nhóc Tỳ"],"blurb":"Thủ pháp liều mạng tự phá một Động Thiên rồi dùng tái diễn để tân sinh, nhằm tìm đường vượt cực hạn mười Động Thiên.","detail":"Nhóc Tỳ tập hợp sức mạnh chín Động Thiên oanh kích một Động Thiên, khiến bản thân phun máu và bị thương nặng. Do pháp tắc áp chế, Động Thiên đã hủy rất khó tân sinh; sau nhiều lần thất bại và trọng thương, nó ngộ mảnh vỡ áo nghĩa đại đạo rồi tái tạo thành công, cuối cùng xây dựng lại hoàn tất mười Động Thiên.","nguon":["@c0225"]},{"id":"thuat-te-song-dong-thien","name":"Thuật tế sống Động Thiên","cn":"","loai":"than-thong","loaiLabel":"Thần thông cấm kị","phamCap":"Cấm kị","hePhai":"Động Thiên cảnh","soHuu":["Nhóc Tỳ"],"blurb":"Thủ đoạn cấm kị được Nhóc Tỳ ngộ ra khi thử dung hợp mười Động Thiên. Bản chất là tế sống thông qua Động Thiên, bị Liễu Thần cảnh báo sẽ thương tổn thiên hòa và gây thiên khiển nếu lạm dụng.","detail":"Trong quá trình suy diễn mười Động Thiên quy nhất, Nhóc Tỳ phát hiện con đường này có xu hướng phân giải chính thân mình, như muốn tế sống bản thân thành một bộ phận của Động Thiên. Liễu Thần xác nhận đây là hướng sai và là thủ đoạn cấm kị; Nhóc Tỳ sau đó hiểu rằng nếu địch nhân dùng Động Thiên tấn công, hắn có thể dựa vào Động Thiên của đối phương để tế sống ngược lại chúng.","nguon":["@c0226"]},{"id":"than-hoan-thap-dai-dong-thien","name":"Thần hoàn thập đại Động Thiên","cn":"","loai":"than-thong","loaiLabel":"Hình thái tu luyện","phamCap":"Cực hạn Động Thiên cảnh","hePhai":"Động Thiên","soHuu":["Nhóc Tỳ"],"blurb":"Hình thái mới sinh ra sau lần đánh cược cuối của Nhóc Tỳ trong Động Thiên cảnh. Mười Động Thiên tương liên quanh thân, hóa thành một vòng thần hoàn to lớn như mặt trời.","detail":"Cuối chương 226, Nhóc Tỳ thiêu đốt sinh mệnh, vận chuyển Phù Văn và tinh khí, khiến mười Động Thiên từ trạng thái va chạm sinh ra liên hệ lẫn nhau. Chúng xoay quanh thân hắn, kết thành một vòng thần hoàn kinh thế, thần hà chiếu cửu thiên, thể hiện biến hóa vượt khỏi hình thái Động Thiên thông thường.","nguon":["@c0226"]},{"id":"than-the-dong-thien","name":"Thân thể Động Thiên","cn":"","aliases":["Thân hóa Động Thiên"],"loai":"luyen-the","loaiLabel":"Thể chất đặc biệt","phamCap":"khong-ro","hePhai":"Thạch Hạo tự khai mở","soHuu":["Thạch Hạo"],"blurb":"Trạng thái đặc biệt sinh ra sau khi thần hoàn thập đại Động Thiên tự động tẩm bổ thân thể Thạch Hạo. Thân thể tuy không phải Động Thiên thật sự nhưng có diệu dụng như Động Thiên, tinh khí tuôn ra liên miên.","detail":"Sau khi thập đại Động Thiên tương liên hóa thần hoàn, thần lực tinh hoa truyền vào thân thể Thạch Hạo, tạo thành quang đoàn chói mắt như mặt trời trong cơ thể. Đại Hồng Điểu và Nhị Ngốc Tử nhận ra đây là trạng thái thần hoàn tự dưỡng thành thân thể Động Thiên, giúp thân thể hắn liên tục được tinh khí bồi đắp.","nguon":["@c0227"]},{"id":"bao-thuat-doc-nhat","name":"Bảo thuật độc nhất","cn":"","aliases":["Mỗi Động Thiên một loại bảo thuật"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"khong-ro","hePhai":"Thạch Hạo tự tẩm bổ","soHuu":["Thạch Hạo"],"blurb":"Thần thông được Thạch Hạo cho rằng sẽ tự tẩm bổ trong các Động Thiên và quang đoàn trong thân thể mình. Nó gắn với Chí Tôn Cốt và quá trình trọng sinh, niết bàn về sau.","detail":"Thạch Hạo nói mỗi Động Thiên có thể dưỡng một loại bảo thuật, quang đoàn trong thân sẽ tẩm bổ ra bảo thuật độc nhất vô nhị thuộc về chính mình. Lão tộc trưởng liên hệ điều này với Chí Tôn Cốt, cho rằng sau khi bảo cốt trọng sinh hoặc niết bàn, thần thông hiển hóa sẽ càng bất phàm.","nguon":["@c0227"]},{"id":"thuong-co-dai-tran-tinh-tho","name":"Thượng cổ đại trận Tịnh Thổ","aliases":["Cấm trận Tịnh Thổ"],"cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"thượng cổ cấm trận","hePhai":"Võ Vương Phủ","soHuu":["Võ Vương Phủ"],"blurb":"Trận cấm kỵ trong Tịnh Thổ Võ Vương Phủ, được kích hoạt khi kỷ lục bia của Thạch Nghị bị phá nát. Phù văn đan dệt như lôi điện, nhốt Nhóc Tỳ ở trung tâm để chờ cường giả tới vây.","detail":"Thượng cổ đại trận Tịnh Thổ là thủ đoạn phòng hộ của Võ Vương Phủ trong Hư Thần Giới. Khi Nhóc Tỳ làm vỡ bia kỷ lục của Thạch Nghị, người trong phủ kích hoạt cấm trận, dùng phù văn phong tỏa khu vực và nhốt hắn ở trung tâm, đồng thời gọi cường giả từ thế giới hiện thực sang ứng phó.","nguon":["@c0229"]},{"id":"tran-phap-te-linh-thuong-co","name":"Trận pháp Tế Linh Thượng Cổ","cn":"","loai":"than-thong","loaiLabel":"Trận pháp","phamCap":"Thượng Cổ tổ trận","hePhai":"Võ Vương Phủ, Thạch Quốc","soHuu":["Võ Vương Phủ"],"blurb":"Trận pháp Tế Linh Thượng Cổ là tổ trận do Tế Linh Thạch Quốc lưu lại, được Võ Vương Phủ nắm giữ. Khi kích hoạt, phù văn đầy trời tập trung công kích người đứng trên mắt trận.","detail":"Đại trận này gắn với vị Tế Linh được cả Thạch Quốc tế bái, được mô tả có uy lực đạt cực hạn mà thế giới cho phép. Thạch Lạp phát động trận để giết Nhóc Tỳ, nhưng Nhóc Tỳ dùng mười tòa Động Thiên giao hòa thành thần hoàn, lấy bản thể nghiền nát phù văn và mặt đất khiến đại trận cạn thần lực rồi bị phá giải.","nguon":["@c0230"]},{"id":"thap-dai-dong-thien","name":"Thập đại Động Thiên","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Chưa rõ","hePhai":"Không rõ nguồn gốc","soHuu":["Thạch Hạo"],"blurb":"Mười Động Thiên của Thạch Hạo nối liền thành một vòng ánh sáng, cách tu hành thần bí không có trong sách cổ.","detail":"Mười Động Thiên nối liền thành một vòng ánh sáng, bồi dưỡng cho cả Động Thiên, vô cùng thần bí; ngay cả sách cổ cũng không trình bày về những vấn đề tương quan. Đây là nền tảng khiến Thạch Hạo đột phá Hóa Linh Cảnh vẫn cực kỳ yêu nghiệt.","nguon":["@c0231"]},{"id":"than-hoan-than-thong","name":"Thần hoàn","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Không rõ","soHuu":["Thạch Hạo"],"blurb":"Thần hoàn chói mắt giang ra cố định đối thủ tại chỗ khiến chúng không nhúc nhích được.","detail":"Khi cứu thôn nhỏ khỏi giặc cỏ, Thạch Hạo giương thần hoàn chói mắt cố định toàn bộ đám giặc tại chỗ, để dân thôn tự tay giết sạch.","nguon":["@c0231"]},{"id":"doi-canh-con-bang","name":"Đôi cánh Côn Bằng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Côn Bằng","soHuu":["Thạch Hạo"],"blurb":"Đôi cánh sau lưng Thạch Hạo, đập mạnh để ngừng thế lao khi nhảy từ trên cao xuống.","detail":"Thạch Hạo dùng đôi cánh Côn Bằng ở sau lưng đập mạnh để giảm và dừng thế lao khi nhảy từ đỉnh núi xuống, tránh đập nát mặt đất.","nguon":["@c0231"]},{"id":"bao-thuat-con-bang","name":"Bảo thuật Côn Bằng","loai":"than-thong","loaiLabel":"Thần thông / Bảo thuật","phamCap":"Trục truyện (bất truyền)","hePhai":"Côn Bằng","soHuu":[],"blurb":"Bảo thuật thần thông thuộc Côn Bằng, mục tiêu chuyến ra biển của Thạch Hạo. Muốn học phải mở được thông đạo cấm kỵ của Côn Bằng, mà chỉ người mười Động Thiên mới mở được.","detail":"Bảo thuật Côn Bằng là mục tiêu Thạch Hạo cùng đám thần bộc lặn lội ra biển để tìm. Điểm mấu chốt là phải mở một thông đạo cấm kỵ của Côn Bằng, việc chỉ người sở hữu mười Động Thiên như Thạch Hạo mới làm được, khiến thần bộc Hoàng Kim Thú buộc phải cầu cạnh nó.","nguon":["@c0232","@c0234"]},{"id":"cau-than-dan-duong","name":"Cầu thần dẫn đường","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thái Cổ Thần Sơn","soHuu":["Thần bộc Hoàng Kim Thú"],"blurb":"Thần thông của thần bộc Hoàng Kim Thú, tỏa bảo quang tạo một thông đạo rực rỡ ép sát mặt đất như cây cầu thần để dẫn đường xa.","detail":"Khi dẫn đường cho Thạch Hạo, thần bộc Hoàng Kim Thú tỏa bảo quang tạo thông đạo rực rỡ ép sát mặt đất tựa một cây cầu thần; cổ mộc, núi đá, khe nước đều không cản được, giúp di chuyển đường xa nhanh chóng.","nguon":["@c0232"]},{"id":"thong-dao-lieu-than","name":"Thông đạo Liễu Thần","loai":"bi-thuat","loaiLabel":"Trận pháp / Dịch chuyển","phamCap":"Không rõ","hePhai":"Liễu Thần","soHuu":["Liễu Thần"],"blurb":"Thủ đoạn dịch chuyển của Liễu Thần: phát sáng, vung mười mấy cành cây tạo phù văn mở một thông đạo xanh mơn mởn ở đầu thôn để đưa người đi đường xa.","detail":"Liễu Thần phát sáng, mười mấy cành cây vung vẫy kết thành phù văn mở ra một thông đạo màu xanh mơn mởn ngay đầu Thạch Thôn, dịch chuyển Thạch Hạo tới vùng Thái Cổ Thần Sơn xa xôi thay vì phải lặn lội một hai năm.","nguon":["@c0232"]},{"id":"tien-hac-phu-van","name":"Tiên hạc phù văn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Liên minh các thế lực Thần Sơn","soHuu":["Thiếu niên Hóa Linh Cảnh khiêu chiến"],"blurb":"Thần thông của cường giả Hóa Linh Cảnh: hóa thân thành chùm sáng, phù văn ầm ầm triệu một con tiên hạc giang cánh tấn công.","detail":"Thần thông được thiếu niên Hóa Linh Cảnh thi triển khi khiêu chiến Thạch Hạo: thân hóa chùm sáng, phù văn nổi lên ầm ầm triệu ra một con tiên hạc giang cánh lao tới. Tiên hạc bị vòng thần hoàn mười Động Thiên của Thạch Hạo nghiền nát cùng chủ nhân.","nguon":["@c0233"]},{"id":"dai-tran-day-bien-hai-ma","name":"Đại trận đáy biển của Hải Ma","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Hải Ma","soHuu":[],"blurb":"Tòa đại trận dưới đáy biển của Hải Ma dùng phong cấm cả vùng biển.","detail":"Một tòa đại trận dưới đáy biển với ký hiệu thần bí màu xanh lam, sát khí ngập trời, có thể giết chết cả người đang bay trên không. Được dùng để phong cấm vùng biển theo lệnh của Hải Ma tôn giả; thần bộc phải thổi cổ bảo Thần Sơn phá phù văn mới mở được đường trốn thoát.","nguon":["@c0234"]},{"id":"bao-thuat-con-bang-than-thong","name":"Bảo thuật Côn Bằng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông cái thế","hePhai":"Thập Hung","soHuu":[],"blurb":"Thần thông cái thế của Thập Hung, mạnh nhất thời Thái Cổ, mạnh đến mức có thể ảnh hưởng cân bằng thế lực của Hoang Vực. Là mục tiêu tranh đoạt của đoàn Thần Sơn Thái Cổ.","detail":"Bảo thuật Côn Bằng là thần thông cái thế của Thập Hung, được xem là mạnh nhất thời Thái Cổ. Uy lực lớn tới mức nếu chiếm được có thể ảnh hưởng cả cân bằng thế lực của Hoang Vực, nên đoàn hơn ba trăm sinh linh từ Thần Sơn Thái Cổ liều chết tiến vào vùng biển tử vong nơi có thần sào Côn Bằng để tranh đoạt.","nguon":["@c0235"]},{"id":"than-thong-thien-phu-hai-dai-ngan-ha","name":"Thần thông thiên phú (hai dải ngân hà)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Chủng tộc thuần huyết của Thanh Vân","soHuu":["Thanh Vân"],"blurb":"Thủ đoạn thiên phú của chủng tộc Thanh Vân: hai dải ngân hà do phù văn tạo thành, có ma lực giam cầm cố định đối thủ.","detail":"Thanh Vân thi triển hai dải ngân hà do phù văn cấu thành, mang ma lực giam cầm khiến đối thủ như sa vào đầm lầy bị cố định tại chỗ. Hắn dùng nó khóa Thạch Hạo rồi nhảy lên đạp vào đầu, nhưng Thạch Hạo bùng mười Động Thiên nối liền phá tan hai dải ngân hà thoát ra.","nguon":["@c0238"]},{"id":"van-kiem-ban-tay-than-kiem","name":"Vạn kiếm (bàn tay thần kiếm)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Chủng tộc thuần huyết của Thanh Vân","soHuu":["Thanh Vân"],"blurb":"Từ bàn tay Thanh Vân tỏa ra vô số thần kiếm màu xanh, vạn kiếm tề minh, kiếm khí cắt rời tất cả.","detail":"Khi hóa thành chim Thanh Loan, Thanh Vân thi triển vạn kiếm từ bàn tay: vô số thần kiếm màu xanh vạn kiếm tề minh, kiếm khí cắt rời mọi thứ. Cá lớn hình thái Côn Bằng của Thạch Hạo quét văng vạn kiếm nhưng vẫn bị thần kiếm quẹt trúng chảy máu.","nguon":["@c0238"]},{"id":"hinh-thai-con-bang-duoi-dai-duong","name":"Hình thái Côn Bằng dưới đại dương","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Bảo thuật Côn Bằng","soHuu":["Thạch Hạo"],"blurb":"Hình thái Côn Bằng khi ở trong đại dương, uy lực tăng gấp bội nhờ Bắc Hải bên dưới thềm đá.","detail":"Đại dương đen tuôn ra sau lưng Thạch Hạo, cá lớn xuất hiện — hình thái Côn Bằng khi ở trong đại dương. Nhờ bên dưới thềm đá là Bắc Hải chứa tinh khí vô tận, uy lực tăng gấp bội, cá lớn quét văng vạn kiếm của Thanh Vân.","nguon":["@c0238"]},{"id":"loi-hai-toan-nghe","name":"Lôi hải (Toan Nghê)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Di chủng Toan Nghê","soHuu":["Lão bộc di chủng Toan Nghê"],"blurb":"Lão bộc hóa Toan Nghê màu tím xen vàng, mang hàng trăm ngàn tia chớp lôi hải hạ xuống.","detail":"Lão bộc di chủng hóa thành Toan Nghê màu tím xen vàng, tấn công Thạch Hạo bằng lôi hải mang hàng trăm ngàn tia chớp hạ xuống, thể hiện sức mạnh Hóa Linh Cảnh cấp cao dù bị áp chế tu vi.","nguon":["@c0238"]},{"id":"tran-phap-truyen-tong-thai-co","name":"Trận pháp truyền tống Thái Cổ","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Thái Cổ","hePhai":"Côn Bằng","soHuu":["Côn Bằng"],"blurb":"Tòa cổ trận nằm trên dốc đá đỉnh núi, là cơ chế chuyển tiếp tới vùng đất cổ nơi có hang ổ thật của Côn Bằng.","detail":"Sau khi sinh linh leo tới dốc đá và phát hiện cổ sào Côn Bằng đã biến mất, nơi này lộ ra một tòa trận pháp từ Thái Cổ. Trận đưa người rời xa ít nhất bảy tám mươi vạn dặm, tới vùng biển và hòn đảo vàng gần hang ổ thật của Côn Bằng.","nguon":["@c0239"]},{"id":"hoa-linh-canh","name":"Hóa Linh Cảnh","cn":"","loai":"khac","loaiLabel":"Cảnh giới tu luyện","phamCap":"Cảnh giới lớn","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Hóa Linh Cảnh là cảnh giới then chốt sau Động Thiên, trọng ở chữ Hóa: hóa linh tính, đắp nặn chân linh và tái tạo chân ngã.","detail":"Trong cảnh giới này, tu sĩ hóa phù văn vào cơ thể để tẩm bổ thân thể và linh hồn, đồng thời có thể hình thành Linh Thần trong đại Động Thiên, khiến chiến lực không kém chân thân. Thạch Hạo ngộ pháp trong hang ổ Côn Bằng, để mười Động Thiên hiện lên, trong đó hai tòa Côn Bằng và Toan Nghê tỏa khí lành và lột xác ở Hóa Linh Cảnh.","nguon":["@c0243"]},{"id":"than-the-thanh-linh","name":"Thân thể thành linh","cn":"","loai":"cong-phap","loaiLabel":"Bước tu hành","phamCap":"Căn cơ Hóa Linh Cảnh","hePhai":"Hóa Linh Cảnh","soHuu":["Thạch Hạo"],"blurb":"Thân thể thành linh là bước lớn đầu tiên và quan trọng nhất trong Hóa Linh Cảnh. Người tu phải khiến huyết nhục, phủ tạng và xương cốt cùng sinh linh tính, đặt nền cho các bước tu hành kế tiếp.","detail":"Trong chương này, Thạch Hạo ngộ đạo tại hang ổ Côn Bằng, trước hết hóa phù quang trong cơ thể vào huyết nhục, cô đọng tái tạo, sau đó khiến xương cốt cũng biến hóa thông linh. Cảnh giới này rất khó viên mãn; nhiều người chỉ rèn ra thần hi, gột rửa thân thể và rèn gân cốt đã xem là hoàn thành, còn người thật sự thành công mỗi thế hệ chỉ đếm trên đầu ngón tay. Muốn đạt mức viên mãn hơn nữa còn phải tới Linh Thai, có thể hóa cả linh tính của địch thủ khi bị công kích để dùng cho bản thân.","nguon":["@c0244"]},{"id":"thon-ha-tho-tuy-long-hinh-khi-tru","name":"Thôn hà thổ tụy / long hình khí trụ","cn":"","loai":"than-thong","loaiLabel":"Thổ nạp pháp","phamCap":"Không rõ","hePhai":"Hóa Linh Cảnh","soHuu":["Thạch Hạo"],"blurb":"Một trạng thái hô hấp tu luyện khi Thạch Hạo thôn hà thổ tụy, khiến khí trụ hóa long từ mũi lao ra và xoay quanh thân thể.","detail":"Trong quá trình chữa thương và hóa linh, Thạch Hạo hô hấp theo một quy tắc riêng. Long hình khí trụ từ mũi lao ra, vờn quanh thân thể rồi nâng nó lên, biểu hiện sự điều hòa tinh khí và linh tính trong lúc tu hành Hóa Linh Cảnh.","nguon":["@c0244"]},{"id":"to-hop-phu-van-hoa-linh-canh","name":"Tổ hợp phù văn Hóa Linh Cảnh","cn":"","loai":"bi-thuat","loaiLabel":"Kỹ pháp","phamCap":"Hóa Linh Cảnh","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Kỹ pháp sắp xếp và tổ hợp phù văn trong cơ thể ở Hóa Linh Cảnh, giúp thân thể thành Linh vận chuyển lực lượng ổn định hơn.","detail":"Thạch Hạo dựa vào Nguyên Thủy Chân Giải để thấu hiểu hướng đi cốt văn, dùng hoa văn các bộ tộc như Chân Hống, Huyền Vũ, Cùng Kỳ, Đào Ngột để hình thành dấu ấn rực rỡ trong cơ thể. Sau khi tổ hợp thành công, thân thể thành Linh viên mãn và sức chiến đấu tăng mạnh như có nguồn lửa thần phù văn không khô cạn.","nguon":["@c0245"]},{"id":"suc-manh-cam-ky-tu-huy-khi-chet","name":"Sức mạnh cấm kỵ tự hủy khi chết","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông của sinh linh thuần huyết","hePhai":"Thanh Loan nhất mạch","soHuu":["Thanh Vân"],"blurb":"Sức mạnh cấm kỵ tự phát động khi Thanh Loan chết, phá hủy phù văn và bảo thuật trong thân. Nhờ vậy bảo thuật bộ tộc không bị Thạch Hạo đoạt được.","detail":"Khi Thanh Vân dưới bản thể Thanh Loan bị Thạch Hạo bẻ cổ giết chết, sức mạnh cấm kỵ trong cơ thể tự kích hoạt, khiến phù văn vỡ nát và hủy diệt toàn bộ dấu vết bảo thuật. Cơ chế này bảo vệ truyền thừa của sinh linh thuần huyết, đồng thời làm Thạch Hạo tiếc nuối vì không thể thu được bảo thuật Thanh Loan.","nguon":["@c0246"]},{"id":"than-thong-hoa-mua-anh-sang","name":"Thần thông hóa mưa ánh sáng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Chưa rõ","soHuu":["Thiếu nữ áo đen"],"blurb":"Thần thông bí ẩn của thiếu nữ áo đen, khiến thân thể hóa thành màn mưa ánh sáng rồi hợp lại thành người.","detail":"Khi Thạch Hạo vận Thập đại Động Thiên nối thành thần hoàn ép tới, thiếu nữ áo đen chợt biến mất, hóa thành mưa ánh sáng rơi vào trời đêm rồi tái hợp. Biểu hiện này khiến Thạch Hạo và Mao Cầu kinh ngạc, như thể nàng không phải thực thể mà được tạo nên từ hào quang linh tính.","nguon":["@c0247"]},{"id":"co-phap-doc-tam-tu","name":"Cổ pháp đọc tâm tư","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Thiếu nữ áo đen"],"blurb":"Pháp môn giúp dò xét ý nghĩ của đối phương trong khoảnh khắc, nhưng điều kiện thi triển rất khó.","detail":"Thiếu nữ dùng cổ pháp này khi hậu nhân Hải Thần bị Đả Thần Thạch đánh choáng, muốn đoạt lấy Côn Bằng pháp trong đầu hắn. Pháp môn thất bại vì hậu nhân Hải Thần quá mạnh, cho thấy cần làm đối phương suy yếu hoặc bất tỉnh sâu hơn mới dễ thành công.","nguon":["@c0248"]},{"id":"than-chu-khong-che-da-than-thach","name":"Thần chú khống chế Đả Thần Thạch","cn":"","loai":"bi-thuat","loaiLabel":"Thần chú","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Thiếu nữ áo đen","Thạch Hạo"],"blurb":"Đoạn thần chú dùng để khống chế Đả Thần Thạch, khiến nó nghe lệnh và tăng uy lực khi công kích.","detail":"Thiếu nữ truyền thần chú này cho Thạch Hạo sau khi nhận ra Đả Thần Thạch trên tóc hắn. Khi niệm lên, Đả Thần Thạch bị ép đứng yên nghe lời, uy lực đánh trúng tăng mạnh và được dùng để nện choáng hậu nhân Hải Thần.","nguon":["@c0248"]},{"id":"dap-lai-chan-nga","name":"Đắp lại chân ngã","cn":"","loai":"cong-phap","loaiLabel":"Giai đoạn tu luyện","phamCap":"Giai đoạn thứ hai của Hóa Linh Cảnh","hePhai":"Hóa Linh Cảnh","soHuu":["Thạch Hạo"],"blurb":"Giai đoạn thứ hai của Hóa Linh Cảnh, tập trung rèn tinh thần và đắp nặn lại chân linh. Thạch Hạo hoàn thành tới viên mãn sau khi chịu cực dương và cực hàn mài giũa.","detail":"Đắp lại chân ngã là bước tu luyện nguy hiểm trong Hóa Linh Cảnh, đòi hỏi tinh thần và đạo thân hòa hợp, khiến thần thức trải qua thiêu đốt, tan vỡ rồi tái sinh để mở rộng con đường tương lai. Ở chương này, Thạch Hạo dùng chân hỏa Động Cực Dương và chí hàn Vực Huyền Băng để rèn luyện tinh thần nguyên, cuối cùng đạt cảnh giới viên mãn trong truyền thuyết.","nguon":["@c0249"]},{"id":"bao-thuat-ca-den-tu-dien-bien","name":"Bảo thuật cá đen tự diễn biến","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"chưa rõ","hePhai":"Thạch Hạo tự diễn biến từ phù văn","soHuu":["Thạch Hạo"],"blurb":"Thần thông do Thạch Hạo thi triển, sau lưng hiện đại dương đen mênh mông và cá lớn do phù văn thai nghén. Nó bị người ngoài nhầm là bảo thuật Côn Bằng nhưng được Tôn Giả xác nhận là tự mình diễn biến.","detail":"Khi đối đầu lão bộc Thái Cổ Di Chủng, Thạch Hạo triển khai phù văn khiến sau lưng hóa thành đại dương đen, trong đó có một con cá cực lớn sinh ra từ tinh túy phù văn và tạo sóng ngập trời. Một Tôn Giả phân biệt đây không phải bảo thuật Côn Bằng vô địch thời Thái Cổ mà là diễn biến riêng của Thạch Hạo; chiêu này đánh bay bản thể mèo vàng lớn như núi của lão bộc, khiến hắn xương cốt đứt gãy, huyết nhục lẫn lộn.","nguon":["@c0251"]},{"id":"vong-xoay-mau-vang","name":"Vòng xoáy màu vàng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"chưa rõ","hePhai":"Thạch Hạo","soHuu":["Thạch Hạo"],"blurb":"Thần thông Thạch Hạo dùng khi xông vào giữa đám Hải Tộc. Vòng xoáy vàng cuốn các sinh linh mạnh nhất vào rồi tạo cơ hội cho hắn điểm ngón tay xuyên thủng mi tâm.","detail":"Trong lúc đám Hải Tộc hô hào đánh giết, trước người Thạch Hạo hiện vòng xoáy màu vàng, cuốn những sinh linh mạnh nhất như Hải Giao, Ngân Sa và Đại Hải Quy vào trong. Hắn điểm ngón tay khiến mi tâm các mục tiêu vỡ nát, rồi thu xác vào Túi Càn Khôn.","nguon":["@c0251"]},{"id":"than-thong-thanh-loan","name":"Thần thông Thanh Loan","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Nhất mạch Thanh Loan","soHuu":["Nam tử tóc xanh nhất mạch Thanh Loan"],"blurb":"Thần thông của nhất mạch Thanh Loan, diễn hóa thần cầm cánh xanh cùng lửa xanh ngập trời.","detail":"Nam tử tóc xanh dùng thần thông này để giao chiến với Thạch Hạo, hóa ra thần cầm cánh xanh mang vô tận lửa xanh. Khi bị áp chế, hắn còn hóa thân thành Thanh Loan để thoát khỏi tràng vực thần hoàn, nhưng sau đó bị Côn Bằng chém rơi một cánh.","nguon":["@c0252"]},{"id":"hai-than-nhat-tram","name":"Hải Thần Nhất Trảm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Tuyệt kỹ Hải Thần nhất mạch","hePhai":"Hải Thần nhất mạch","soHuu":["Mạc Thương"],"blurb":"Tuyệt kỹ Mạc Thương thi triển trong trận đại chiến trên tế đàn với Thạch Hạo.","detail":"Khi thi triển, Mạc Thương dùng thân pháp xoay chuyển, chân tạo vòng xoáy rồi há miệng phun ra luồng hào quang phù văn cực chói. Chiêu này được dùng để áp chế Thạch Hạo trong lúc hai bên giao phong cận thân.","nguon":["@c0253"]},{"id":"thien-nhan-hop-nhat","name":"Thiên nhân hợp nhất","cn":"","loai":"bi-thuat","loaiLabel":"Trạng thái chiến đấu","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Mạc Thương"],"blurb":"Trạng thái chiến đấu giúp Mạc Thương mượn lực trời đất trong trận với Thạch Hạo.","detail":"Mạc Thương bước vào trạng thái này khi trận chiến leo thang, khiến tinh khí phù văn bát hoang dung nhập vào thân thể và tăng cường thế công bằng đại kích màu vàng. Đây là lợi thế được người xem xem như biểu hiện của Hóa Linh Cảnh viên mãn.","nguon":["@c0253"]},{"id":"dinh-cam-co-hu-khong","name":"Định","cn":"","aliases":["Cầm cố hư không"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thạch Hạo","soHuu":["Thạch Hạo"],"blurb":"Thần thông cầm cố không gian do Thạch Hạo thi triển trong động phủ đáy biển Côn Bằng.","detail":"Khi bị nhiều cường giả liên hợp vây công, Thạch Hạo hô Định khiến hư không bị khóa, địch nhân giữ nguyên tư thế không thể động đậy, ngay cả bảo cụ đang phát sáng cũng bị cầm cố.","nguon":["@c0254"]},{"id":"bi-phap-cam-ky-mac-thuong","name":"Bí pháp cấm kỵ","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Hải Thần nhất mạch","soHuu":["Mạc Thương"],"blurb":"Bí pháp Mạc Thương dùng để thoát thân khi bị Thạch Hạo đấm xuyên ngực.","detail":"Mạc Thương thi triển bí pháp cấm kỵ, toàn thân phát sáng như đang thiêu đốt để thoát khỏi nắm đấm xuyên ngực của Thạch Hạo, nhưng vẫn để lại thương thế cực nặng.","nguon":["@c0254"]},{"id":"muoi-toa-dong-thien-hoa-than-hoan","name":"Mười tòa Động Thiên hóa thần hoàn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Thạch Hạo thúc dục mười tòa Động Thiên hóa thành thần hoàn, quét ra ô quang chém địch trong động phủ Côn Bằng.","detail":"Khi tranh đoạt bồ đoàn côn mộc, Thạch Hạo dùng mười tòa Động Thiên hóa thần hoàn để phát ra ô quang, một đòn chém ngang một đám cường giả. Lúc cuồng bạo, mười Động Thiên còn được mô tả như những mặt trời chói mắt, cơ thể Động Thiên phun ra tinh khí.","nguon":["@c0256"]},{"id":"phu-van-con-bang","name":"Phù văn Côn Bằng","cn":"","loai":"than-thong","loaiLabel":"Phù văn truyền thừa","phamCap":"Truyền thừa Thái Cổ","hePhai":"Côn Bằng","soHuu":["Thạch Hạo"],"blurb":"Các ký hiệu vàng và đen mang áo nghĩa Côn Bằng, vừa là chìa khóa an toàn đi trong Hóa Ma động, vừa là nội dung truyền thừa dung hợp với thân thể người tu.","detail":"Phù văn Côn Bằng gồm hàng ngàn vạn ký hiệu vàng và đen, mang pháp tắc và áo nghĩa của Côn Bằng. Với Thạch Hạo, chúng vừa là chìa khóa giúp nó vận chuyển đúng con đường Côn Bằng để vượt qua các cấm chế đủ nghiền nát Tôn Giả trong Hóa Ma động, vừa là nội dung truyền thừa hoàn chỉnh. Ở ao máu cuối động, phù văn tổ hợp thành Côn Bằng, côn ngư, chim bằng rồi lao vào thân Thạch Hạo, ngưng tụ thành lớp chiến y thần thánh hữu hình bao ngoài cơ thể.","nguon":["@c0261"]},{"id":"con-duong-cua-con-bang","name":"Con đường của Côn Bằng","cn":"","loai":"cong-phap","loaiLabel":"Pháp môn / Đường tu","phamCap":"Truyền thừa Thái Cổ","hePhai":"Côn Bằng","soHuu":["Thạch Hạo"],"blurb":"Con đường tu hành năm xưa của Côn Bằng mà Thạch Hạo đã đi theo từ hai năm trước, giúp tiếp cận phù văn kỳ dị và vượt Hóa Ma động.","detail":"Từ hai năm trước, Thạch Hạo đã đi trên con đường tu hành của Côn Bằng, nhờ đó tiếp cận được hoàn cảnh tu hành năm xưa của sinh linh này. Chính con đường ấy giúp nó quan sát được phù văn kỳ dị trong thần sào, truyền phù văn vào Côn Bằng cốt để biết bí mật Hóa Ma động, và vận chuyển phù văn đúng cách để đi an toàn qua các cấm chế trong động.","nguon":["@c0261"]},{"id":"ba-buoc-hoa-linh-canh-tron-ven","name":"Ba bước Hóa Linh cảnh trọn vẹn","cn":"","aliases":["Thân thể thành linh, Trọng tố chân ngã, Động thiên dưỡng linh"],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Ba giai đoạn viên mãn của Hóa Linh cảnh gồm Thân thể thành linh, Trọng tố chân ngã và Động thiên dưỡng linh. Đây là con đường cực khó, trong Hoang Vực hầu như không ai thật sự đi trọn vẹn.","detail":"Ba bước Hóa Linh cảnh trọn vẹn được nêu là Thân thể thành linh, Trọng tố chân ngã và Động thiên dưỡng linh. Các bước này chỉ có thể tiếp cận vô hạn, gần như không thể thật đạt tới; cả Hoang Vực khó có người làm được. Sau khi chiếm được pháp Côn Bằng để dưỡng linh, Thạch Hạo hoàn thành bước Động Thiên Dưỡng Linh, khiến ba bước Hóa Linh cảnh của mình đi tới trọn vẹn.","nguon":["@c0262"]},{"id":"dong-thien-duong-linh","name":"Động Thiên dưỡng Linh","cn":"","loai":"cong-phap","loaiLabel":"Pháp môn tu luyện","phamCap":"Ranh giới truyền thuyết trong Hóa Linh Cảnh","hePhai":"Động Thiên · Hóa Linh","soHuu":["Thạch Hạo"],"blurb":"Pháp môn dùng Động Thiên làm nơi nuôi dưỡng linh thân, khiến mười Động Thiên của Thạch Hạo đều sinh linh tính. Tại ao máu Côn Bằng, pháp môn này được đẩy tới viên mãn truyền thuyết.","detail":"Thạch Hạo dung hợp chân huyết, phù văn và áo nghĩa Côn Bằng vào linh thân Côn Bằng trong một Động Thiên, rồi tiếp tục tế luyện Toan Nghê cùng các hình thái linh tính khác. Sau nhiều tháng, mười Động Thiên đều dưỡng Linh thành công, xác lập mốc viên mãn của Hóa Linh Cảnh.","nguon":["@c0263"]},{"id":"linh-than-con-bang","name":"Linh thân Côn Bằng","cn":"","loai":"than-thong","loaiLabel":"Linh thân Động Thiên","phamCap":"Không rõ","hePhai":"Côn Bằng · Động Thiên","soHuu":["Thạch Hạo"],"blurb":"Linh thân Côn Bằng trong một Động Thiên của Thạch Hạo, được nuôi dưỡng bằng chân huyết và phù văn Côn Bằng. Sau dung hợp, nó trở nên linh động và có uy thế như chân linh thức tỉnh.","detail":"Trong ao máu, ký hiệu vàng đen cùng áo nghĩa phù văn còn sót lại của Côn Bằng dung hợp với linh thân trong Động Thiên. Linh thân này vì thế tăng mạnh, giúp Thạch Hạo mở đường rời Hóa Ma Động sau khi bế quan.","nguon":["@c0263"]},{"id":"linh-than-toan-nghe","name":"Linh thân Toan Nghê","cn":"","loai":"than-thong","loaiLabel":"Linh thân Động Thiên","phamCap":"Không rõ","hePhai":"Toan Nghê · Động Thiên","soHuu":["Thạch Hạo"],"blurb":"Một linh thân trong Động Thiên của Thạch Hạo mang hình Toan Nghê. Nó được tế luyện tiếp trong quá trình hoàn tất mười Động Thiên dưỡng Linh.","detail":"Sau khi linh thân Côn Bằng dung hợp truyền thừa, Thạch Hạo tiếp tục tế luyện các Động Thiên khác; trong đó có Động Thiên hiện Toan Nghê ngẩng đầu huýt dài, góp phần hoàn thiện dưỡng Linh.","nguon":["@c0263"]},{"id":"suc-dia-thanh-thon","name":"Súc địa thành thốn","cn":"","loai":"than-thong","loaiLabel":"Thân pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Thạch Trung Thiên"],"blurb":"Thân pháp thần diệu giúp một bước đi được trăm trượng, khiến người dùng biến mất trên đường lớn.","detail":"Thập Ngũ gia dùng thân pháp này để rời đi sau khi gây chấn động cửa thành Hoàng Đô, một bước chính là trăm trượng, thoáng chốc biến mất trên đường lớn.","nguon":["@c0265"]},{"id":"tam-dai-sat-tran-trong-toc","name":"Tam đại sát trận trong tộc","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Trận tổ truyền","hePhai":"Võ Vương phủ","soHuu":[],"blurb":"Ba bộ sát trận tổ truyền của Võ Vương phủ, bố trí trong cung điện để vây nhốt và giết đối thủ mạnh.","detail":"Được bố trí trong cung điện Võ Vương phủ để vây giết Thập Ngũ gia, kích hoạt khi cung điện vỡ nát, hiện ra trận văn dày đặc cùng Giao Long và Bệ Ngạn; là phần tinh hoa tổ trận khác với trận văn năm xưa Thạch Tử Lăng từng phá, nhưng cuối cùng bị Thập Ngũ gia phá tan.","nguon":["@c0266"]},{"id":"huyen-cong","name":"Huyền công","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Võ Vương phủ","soHuu":["Võ Vương"],"blurb":"Công pháp giúp dung mạo Võ Vương nhiều năm không đổi, vẫn như hơn bốn mươi tuổi và tinh lực chưa suy yếu.","detail":"Được dùng để giải thích vì sao dung mạo Võ Vương nhiều năm không đổi, vẫn như hơn bốn mươi tuổi và tinh lực chưa suy yếu như bốn vị lão tổ.","nguon":["@c0269"]},{"id":"bao-thuat-thuong-luong-xam","name":"Bảo thuật thuồng luồng xám","aliases":[],"loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"Không rõ","hePhai":"Võ Vương phủ","soHuu":["Võ Vương"],"blurb":"Bảo thuật Võ Vương phất tay áo hóa ra con thuồng luồng cổ xưa màu xám, khổng lồ như núi.","detail":"Võ Vương phất tay áo hóa ra một con thuồng luồng cổ xưa màu xám, khổng lồ như núi, có khí tức gần như sinh mệnh, để đối kháng đại bàng cánh vàng của Thập Ngũ gia.","nguon":["@c0269"]},{"id":"bao-thuat-dai-bang-canh-vang","name":"Bảo thuật đại bàng cánh vàng","aliases":["Kim Sí Đại Bàng"],"loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"Không rõ","hePhai":"Thạch tộc","soHuu":["Thạch Trung Thiên"],"blurb":"Bảo thuật của Thập Ngũ gia khiến sau lưng bay lên đại bàng cánh vàng rực, dùng móng vuốt chụp vào đối thủ.","detail":"Thập Ngũ gia khiến sau lưng bay lên đại bàng cánh vàng rực, dùng móng vuốt lớn chụp vào thuồng luồng xám của Võ Vương. Trước đó ông cũng dùng Kim Sí Đại Bàng trấn áp nhất mạch Thạch Nghị.","nguon":["@c0269"]},{"id":"the-gioi-trong-long-ban-tay","name":"Thế giới trong lòng bàn tay","aliases":[],"loai":"than-thong","loaiLabel":"Đại thần thông","phamCap":"Cao","hePhai":"Võ Vương phủ","soHuu":["Võ Vương"],"blurb":"Đại thần thông của Võ Vương biến bàn tay thành một thế giới có nhật nguyệt tinh thần, dùng để trấn áp rồi luyện hóa đối thủ.","detail":"Thần thông của Võ Vương biến bàn tay thành một thế giới có sương mù, nhật nguyệt tinh thần và đại tinh phù văn, dùng để trấn áp Đại Ma Thần; khi hô Hóa thì biến thành lò lửa liên hệ với lư đồng để luyện hóa địch.","nguon":["@c0270"]},{"id":"hac-than-phong","name":"Hắc Thần Phong","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cao","hePhai":"Võ Vương phủ","soHuu":["Võ Vương"],"blurb":"Thần thông Võ Vương phóng hắc phong từ ống tay áo, âm nhu nhưng có uy lực cắn nát sông núi.","detail":"Võ Vương phóng hắc phong từ ống tay áo, âm nhu nhưng có uy lực cắn nát sông núi, quấn nát Bệ Ngạn hoàng kim do bảo thuật của Đại Ma Thần hóa thành.","nguon":["@c0270"]},{"id":"hon-don-dai-khi-cong","name":"Hỗn Độn Đại Khí công","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp luyện khí","phamCap":"Gần như thất truyền","hePhai":"","soHuu":["Thạch Trung Thiên"],"blurb":"Công pháp gần như thất truyền, luyện khí hỗn độn vào cơ thể và nội liễm phù văn bản nguyên.","detail":"Công pháp gần như thất truyền, luyện khí hỗn độn vào cơ thể và nội liễm phù văn bản nguyên; Đại Ma Thần phun ra khí mờ cuồng bạo đánh tan Hắc Thần Phong. Ít người ở Thạch Quốc hiểu môn công pháp này.","nguon":["@c0270"]},{"id":"be-ngan-hoang-kim","name":"Bệ Ngạn hoàng kim","aliases":["Bệ Ngạn"],"loai":"bi-thuat","loaiLabel":"Bảo thuật","phamCap":"Không rõ","hePhai":"Thạch tộc","soHuu":["Thạch Trung Thiên"],"blurb":"Bảo thuật Đại Ma Thần đánh ra kình khí xoắn ốc hóa thành Bệ Ngạn hoàng kim chi chít vảy, mang sức mạnh như hung thú thật.","detail":"Đại Ma Thần đánh ra kình khí xoắn ốc hóa thành Bệ Ngạn hoàng kim chi chít vảy, mang sức mạnh như hung thú thật để công kích Võ Vương.","nguon":["@c0270"]},{"id":"than-tien-vo-song","name":"Thần tiễn vô song","aliases":[],"loai":"bi-thuat","loaiLabel":"Tiễn thuật/Thần thông","phamCap":"Cao","hePhai":"Thạch tộc","soHuu":["Thạch Trung Thiên"],"blurb":"Tiễn thuật đỉnh cao của Thập Ngũ gia, dùng một tay và ống tay áo bên tay cụt kéo cung, bắn xuyên Kim Ô phù văn và trọng thương Võ Vương.","detail":"Thập Ngũ gia dùng một tay và ống tay áo bên tay cụt kéo cung, các mũi tên xuyên thủng và tự đổi hướng truy kích mục tiêu, giết sạch sáu Kim Ô phù văn, làm móp lư đồng Thượng Cổ và cuối cùng trọng thương Võ Vương. Người quan chiến nhận xét ông vẫn chưa phát huy ra uy năng chân chính.","nguon":["@c0271"]},{"id":"huyet-ho-than-thong","name":"Huyết hồ thần thông","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cao","hePhai":"Võ Vương phủ","soHuu":["Võ Vương"],"blurb":"Thần thông Võ Vương dùng máu tươi hóa thành hồ máu có phù văn dày đặc để bao phủ và luyện hóa đối thủ.","detail":"Võ Vương dùng máu tươi hóa thành hồ máu có phù văn dày đặc để bao phủ và luyện hóa Thập Ngũ gia, thu gom tinh khí mười phương, nhưng bị Thập Ngũ gia hóa đỉnh thu luyện thành huyết đan.","nguon":["@c0271"]},{"id":"than-tinh-ma-tinh-trang-den","name":"Thần tính và ma tính trắng-đen","aliases":[],"loai":"cong-phap","loaiLabel":"Trạng thái tu hành","phamCap":"Cao","hePhai":"Thạch tộc","soHuu":["Thạch Trung Thiên"],"blurb":"Trạng thái Thập Ngũ gia phóng thích hai luồng sáng trắng an lành và đen lạnh lẽo từ hai chân, thần tính và ma tính hòa quyện toàn thân.","detail":"Thập Ngũ gia phóng thích hai luồng sáng trắng an lành và đen lạnh lẽo từ hai chân, khiến chiến lực tăng mạnh; chương xác nhận danh hiệu Đại Ma Thần không chỉ do phong cách hành sự mà còn liên quan đến con đường tu hành thần-ma.","nguon":["@c0271"]},{"id":"mua-phu-van-cua-vu-toc","name":"Mưa phù văn của Vũ tộc","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Vũ tộc","soHuu":["Vũ Vương"],"blurb":"Thần thông Vũ Vương khiến trời đổ mưa không tự nhiên, hơi nước chứa phù văn bao phủ Võ Vương phủ và có thể hóa thành công kích.","detail":"Vũ Vương khiến trời đổ mưa không tự nhiên, hơi nước chứa phù văn bao phủ Võ Vương phủ và có thể hóa thành công kích; mưa của Vũ tộc phủ xuống mang ý nghĩa uy hiếp.","nguon":["@c0272"]},{"id":"chan-hong-khieu","name":"Chân Hống khiếu","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Vũ Vương / Vũ tộc","soHuu":["Vũ Vương"],"blurb":"Âm ba công của Vũ Vương, âm thanh như sấm chấn động cả tòa thành lớn, truyền khắp Hoàng Đô.","detail":"Công pháp âm thanh Vũ Vương thi triển khi khai chiến với Đại Ma Thần; tiếng gầm truyền vang khắp Hoàng Đô.","nguon":["@c0273"]},{"id":"hac-long-bach-long-chi-khi","name":"Hắc long bạch long chi khí","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Đại Ma Thần (Thạch Trung Thiên)","soHuu":["Thạch Trung Thiên"],"blurb":"Đại Ma Thần bắn hai cột khí hình rồng (một hắc một bạch) từ hai mắt, phóng lớn đè ép thiên địa, nuốt sấm chớp.","detail":"Từ hai mắt Đại Ma Thần bắn ra một hắc long và một bạch long, nhanh chóng phóng lớn, áp đảo Vũ Vương trong đại chiến ở Võ Vương phủ.","nguon":["@c0273"]},{"id":"tay-ma","name":"Tay ma","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"đại thần thông","hePhai":"Con đường Thần Ma của Đại Ma Thần","soHuu":["Thạch Trung Thiên"],"blurb":"Tay ma là đại thần thông của Đại Ma Thần, hiện thành bàn tay đen khổng lồ như Ngũ Chỉ sơn. Trong trận với Vũ Vương, nó đè ép lôi điện và đánh tan phù văn trên người đối thủ.","detail":"Thần thông này tạo ra bàn tay đen ánh sáng lấp lánh, cường thế đến mức kiếm quang khó chém đứt. Thạch Trung Thiên dùng Tay ma áp chế Vũ Vương trong giai đoạn đầu trận, đập tan mưa máu và buộc Vũ Vương liên tục rút lui.","nguon":["@c0274"]},{"id":"tay-than","name":"Tay thần","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"đại thần thông","hePhai":"Con đường Thần Ma của Đại Ma Thần","soHuu":["Thạch Trung Thiên"],"blurb":"Tay thần là đại thần thông trong truyền thuyết, biểu hiện thành bàn tay trắng bóng như ngọc. Đây là bước tiếp sau Tay ma trên con đường Thần Ma của Thạch Trung Thiên.","detail":"Khi chín hồ lô đỏ nổ tung thành mảnh vỡ, Thạch Trung Thiên chuyển bàn tay từ đen sang trắng như ngọc và dùng Tay thần đánh tan mảnh vỡ thành bụi trần, dập tắt cơn bão năng lượng. Chương nhấn mạnh thần thông này nhiều năm chưa xuất hiện.","nguon":["@c0274"]},{"id":"dai-tran-mua-mau","name":"Đại trận mưa máu","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"đại trận sát phạt tổ truyền","hePhai":"Vũ tộc","soHuu":["Vũ Vương","Vũ tộc"],"blurb":"Đại trận mưa máu là đại trận sát phạt tổ truyền của Vũ tộc. Vũ Vương kích hoạt nó bằng máu của mình để đối kháng Đại Ma Thần.","detail":"Mỗi hạt mưa máu trong trận chứa tinh thần sinh mệnh của Vũ Vương, hóa thành phù văn và ánh kiếm. Khi chín hồ lô đỏ phối hợp phun ánh kiếm, dư âm trận pháp còn làm nổ tung một ngọn núi ngoài Hoàng Đô, thể hiện uy lực đủ uy hiếp cả thành trì và đại quân.","nguon":["@c0274"]},{"id":"phu-van-phong-ho-vu-vuong-phu","name":"Phù văn phòng hộ Vũ Vương phủ","cn":"","loai":"khac","loaiLabel":"Trận/phù văn","phamCap":"Không rõ","hePhai":"Vũ tộc","soHuu":["Vũ tộc"],"blurb":"Hệ phù văn phòng hộ được bố trí trong các khu quan trọng của Vũ Vương phủ. Khi Đại Ma Thần bắn phá, lớp phòng hộ này vẫn bị mũi tên xuyên phá.","detail":"Phù văn phòng hộ Vũ Vương phủ được kích hoạt tại sân và khu vực trọng yếu của phủ đệ, nhưng không ngăn nổi uy lực cung tên của Thạch Trung Thiên. Các mũi tên phá nát cổng, sân và kiến trúc, khiến khu ngoài phủ thành phế tích trước mắt Hoàng Đô.","nguon":["@c0275"]},{"id":"tran-phap-cua-than-trong-than-mieu-vu-toc","name":"Trận pháp của thần trong thần miếu Vũ tộc","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Thần lưu lại","hePhai":"Vũ tộc","soHuu":["Vũ tộc"],"blurb":"Trận pháp do thần lưu lại trong thần miếu Vũ tộc, được kích hoạt khi Vũ tộc rút vào nơi sâu nhất. Nó bao phủ phủ đệ và chống lại tên thần của Thập Ngũ gia.","detail":"Trận pháp nằm trong thần miếu Vũ tộc, nơi vừa là cấm địa vừa thu nhận pháp chỉ Vũ Thần. Khi Vũ tộc tế bái tượng đá và kích hoạt trận pháp, khói lan ra bao phủ phủ đệ, tạo phòng tuyến đối kháng Đại Ma Thần trước khi thần miếu bị tên thần bắn tới rạn nứt, sụp đổ.","nguon":["@c0275"]},{"id":"trang-vuc-tuong-da-va-te-dan","name":"Tràng vực tượng đá và tế đàn","cn":"","loai":"khac","loaiLabel":"Tràng vực/phong tỏa","phamCap":"Không rõ","hePhai":"Vũ tộc","soHuu":["Vũ tộc"],"blurb":"Tràng vực hình thành từ ánh sáng của tượng đá Vũ Thần và tế đàn sau khi thần miếu sụp đổ. Nó niêm phong phủ đệ, khiến Đại Ma Thần không tiến sâu vào thần thổ Vũ tộc.","detail":"Sau khi ngôi miếu thờ thiêng liêng của Vũ tộc đổ xuống, chỉ còn tượng đá và tế đàn tỏa ánh sáng đáng sợ. Đến phút cuối, ánh sáng này hình thành tràng vực niêm phong cả phủ đệ, trở thành lý do Thạch Trung Thiên dừng tay không tiếp tục tiến vào vùng sâu của Vũ tộc.","nguon":["@c0275"]},{"id":"dong-bang-cuc-han","name":"Đóng băng cực hạn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Thái Cổ Thần Sơn","soHuu":["Bích Ma Hắc Đồng Chu"],"blurb":"Thần thông băng hàn do người tóc xanh thi triển trong Võ Vương phủ.","detail":"Người tóc xanh vận Thái Âm chân lực, dùng hàn khí trắng xóa đóng băng mục tiêu rồi khiến vật thể nổ tan, được mô tả có thể niêm phong thân thể và làm thân thể tử vong, nát vụn.","nguon":["@c0276"]},{"id":"xich-den-trat-tu","name":"Xích đen trật tự","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Thạch Trung Thiên"],"blurb":"Thần thông quy tắc của Đại Ma Thần trong trận chiến với người tóc xanh.","detail":"Thạch Trung Thiên điều khiển rồng đen hóa thành sợi xích đen mang trật tự và quy tắc, quấn chặt đối thủ như hình với bóng, tạo sức xiết trong giao chiến.","nguon":["@c0276"]},{"id":"than-thong-mo-cua-dia-nguc","name":"Thần thông mở cửa địa ngục","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Thái Cổ Thần Sơn","soHuu":["Bích Ma Hắc Đồng Chu"],"blurb":"Thần thông dùng mắt mở ra vùng hư không đen tối như địa ngục.","detail":"Người tóc xanh khiến con ngươi hóa thành phù văn xám như vong hồn, dệt ra một cánh cửa hư không dẫn tới vùng ma quật đen tối đầy bóng đen, nhằm đẩy đối thủ vào trong đó.","nguon":["@c0276"]},{"id":"dong-thien-linh-than","name":"Động Thiên linh thân","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Thạch Trung Thiên","soHuu":["Thạch Trung Thiên"],"blurb":"Thần thông dùng Động Thiên phóng ra nhiều linh thân để vây công đối thủ.","detail":"Trong trận ở Võ Vương phủ, Thạch Trung Thiên mở nhiều Động Thiên, phóng ra các linh thân như Kim Sí Đại Bằng, Toan Nghê, Bệ Ngạn và chim tước đỏ đậm để vây đánh Bích Ma Hắc Đồng Chu.","nguon":["@c0277"]},{"id":"to-nhen-loi-dien-cua-bich-ma-hac-dong-chu","name":"Tơ nhện lôi điện của Bích Ma Hắc Đồng Chu","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Ma Linh hồ","soHuu":["Bích Ma Hắc Đồng Chu"],"blurb":"Thần thông phun tơ bạc đan lôi điện thành lưới phù văn.","detail":"Bích Ma Hắc Đồng Chu phun các sợi tơ bạc kèm lôi điện, kết thành lưới lớn và xích thần phù văn, có thể vây bắt linh thân của Thạch Trung Thiên rồi nuốt chửng.","nguon":["@c0277"]},{"id":"giam-cam","name":"Giam cầm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Ma Linh hồ","soHuu":["Bích Ma Hắc Đồng Chu"],"blurb":"Thần thông dùng mạng nhện phù văn khóa giữ vùng hư không.","detail":"Bích Ma Hắc Đồng Chu phát động mạng nhện phù văn dày đặc để giam giữ vùng trời đất, khiến Thạch Trung Thiên nhất thời không thể động đậy và bị uy hiếp bởi chân nhện.","nguon":["@c0277"]},{"id":"tam-niem-hoa-cung-tien","name":"Tâm niệm hóa cung tiễn","cn":"","loai":"than-thong","loaiLabel":"Thần thông tinh thần lực","phamCap":"không rõ","hePhai":"Thạch Trung Thiên","soHuu":["Thạch Trung Thiên"],"blurb":"Thần thông dùng tâm niệm từ mi tâm hóa thành bảo cung và thần tiễn.","detail":"Khi thân thể bị giam cầm, Thạch Trung Thiên dùng tinh thần lực từ mi tâm hóa thành bảo cung và mũi tên ánh sáng, bắn thủng đầu linh thân Ma Chu để xoay chuyển kết cục trận chiến.","nguon":["@c0277"]},{"id":"sat-tran-phu-cot-phong-an","name":"Sát trận phù cốt phong ấn","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Ma Linh hồ","soHuu":["Bích Ma Hắc Đồng Chu"],"blurb":"Trận pháp dùng các khối cốt phong ấn phủ đệ và trấn áp đối thủ.","detail":"Người tóc xanh dùng các khối cốt phong ấn khu vực Võ Vương phủ và hư không, rồi vận dụng bảo cốt màu tím trấn áp Thạch Trung Thiên như một sát trận.","nguon":["@c0277"]},{"id":"tran-do-da-thu-va-bao-cot-kiem-khi","name":"Trận đồ da thú và bảo cốt kiếm khí","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Thạch Trung Thiên","soHuu":["Thạch Trung Thiên"],"blurb":"Trận pháp phòng thủ phản kích do tấm da thú và bảo cốt kích phát.","detail":"Thạch Trung Thiên tung tấm da thú xoay tròn, phối hợp mấy khối bảo cốt kích phát kiếm khí như thiên kiếm để đối kháng sát trận của Ma Chu.","nguon":["@c0277"]},{"id":"truyen-tong-tran-nhan-ngu-toc","name":"Truyền tống trận Nhân Ngư Tộc","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Nhân Ngư Tộc","soHuu":["Nhân Ngư Tộc"],"blurb":"Trận pháp truyền tống đặt tại tế đàn trung tâm thành trì Nhân Ngư dưới đáy Bắc Hải.","detail":"Truyền tống trận do ông lão trong Nhân Ngư Tộc kích hoạt theo lời nhờ của cô gái Nhân Ngư Tộc, mở thông đạo đưa Thạch Hạo rời thành trì dưới đáy biển về Tây Cương Thạch Quốc.","nguon":["@c0278"]},{"id":"co-phap-thu-liem-khi-the-trong-nguyen-thuy-chan-giai","name":"Cổ pháp thu liễm khí thế trong Nguyên Thủy Chân Giải","cn":"","loai":"bi-thuat","loaiLabel":"Cổ pháp","phamCap":"Không rõ","hePhai":"Nguyên Thủy Chân Giải","soHuu":["Thạch Hạo"],"blurb":"Một cổ pháp trong Nguyên Thủy Chân Giải dùng để làm mờ khí thế chân chính và che giấu khí cơ. Thạch Hạo vận dụng sau khi biết mình bị thần bích cảm ứng.","detail":"Cổ pháp này không phải bảo thuật tấn công mạnh mà thiên về thu liễm, giúp người dùng giữ tinh khí thần không lộ ra ngoài. Thạch Hạo gần đây mới tìm hiểu thấu đáo quy tắc này và lập tức dùng nó để tránh bị người khác nhận ra tiềm năng sau sự việc thần bích phát sáng.","nguon":["@c0280"]},{"id":"bao-thuat-huyen-quy","name":"Bảo thuật Huyền Quy","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"đỉnh cấp bảo thuật phòng ngự","hePhai":"Bộ tộc Huyền Quy","soHuu":["Thạch Hạo"],"blurb":"Bảo thuật Huyền Quy là thần thông phòng ngự khắc trên mai rùa của bộ tộc Huyền Quy. Thạch Hạo đổi được bằng phương thuốc tổ truyền Thạch Thôn trong phòng đấu giá.","detail":"Bảo thuật này chủ về phòng ngự, khi Thạch Hạo thử vận chuyển thì thân thể phát ra hào quang vàng đất, cơ thể trở nên cứng rắn như có xu thế kim cương bất hoại. Nó dự định dùng bồ đoàn Côn Mộc lấy từ sào huyệt Côn Bằng để tiếp tục tham ngộ.","nguon":["@c0283"]},{"id":"phu-van-giao-thu","name":"Phù văn giao thủ","cn":"","loai":"than-thong","loaiLabel":"Thần thông/phù văn","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Tiên tử che mặt","Thiên Hồ tiên tử"],"blurb":"Lối giao chiến bằng phù văn giữa Tiên tử che mặt và Thiên Hồ tiên tử, bề ngoài không ầm ĩ nhưng cực kỳ nguy hiểm.","detail":"Hai bên thi triển phù văn như đóa hoa tiên đủ màu sắc, va chạm tạo gợn sóng có thể nghiền nát bảo cụ. Trận giao thủ ngắn ngủi kết thúc bằng việc tấm lụa che mặt của Tiên tử che mặt bị lật, lộ nửa dung nhan.","nguon":["@c0286"]},{"id":"bong-huyen-quy-tran-ap","name":"Bóng huyền quy trấn áp","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"khong-ro","hePhai":"Thạch Hạo","soHuu":["Thạch Hạo"],"blurb":"Bóng huyền quy trấn áp là thủ đoạn Thạch Hạo thi triển khi giao chiến với thiếu niên quý tộc trên chiến xa. Bàn tay phải hóa đen, hiện bóng mờ huyền quy ép đối thủ ngã lăn.","detail":"Trong cuộc xung đột trên đường tới Thanh Lâm viên, Thạch Hạo dùng thủ đoạn này để nhanh chóng áp chế thiếu niên chủ nhân chiến xa. Thần thông tạo bóng huyền quy mang uy thế trấn áp trực diện, phối hợp với đòn tia chớp tím để đánh tan cả nhóm thiếu niên.","nguon":["@c0288"]},{"id":"tia-chop-mau-tim","name":"Tia chớp màu tím","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"khong-ro","hePhai":"Thạch Hạo","soHuu":["Thạch Hạo"],"blurb":"Tia chớp màu tím là đòn công kích bằng lôi điện của Thạch Hạo trong trận cướp chiến xa. Đòn này đánh trúng nhóm thiếu niên khiến cả người họ bốc khói đen.","detail":"Sau khi dùng bóng huyền quy trấn áp thiếu niên chủ nhân chiến xa, Thạch Hạo tiếp tục phóng tia chớp tím vào nhóm thiếu niên còn lại. Đòn đánh có sức áp chế nhanh, giúp hắn quét sạch đối thủ và chiếm chiến xa.","nguon":["@c0288"]},{"id":"kim-si-bang-dieu","name":"Kim Sí Bằng Điểu","cn":"","aliases":["bảo thuật không đầy đủ"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Thạch Hạo"],"blurb":"Kim Sí Bằng Điểu là bảo thuật không đầy đủ được Thạch Hạo dùng để áp chế tám hung thú kéo xe. Nó mang uy áp chủng tộc khiến hung thú không dám phản kháng.","detail":"Khi chiếm chiến xa thanh đồng của Lăng Vân hầu, Thạch Hạo không thi triển Bảo thuật Côn Bằng hoàn chỉnh mà dùng một bảo thuật không đầy đủ hiện hình Kim Sí Bằng Điểu. Cách dùng này giúp nó chế phục tám hung thú kéo xe, đồng thời tránh để lộ truyền thừa Côn Bằng và chuốc họa sát thân.","nguon":["@c0289"]},{"id":"kim-cuong-bat-hoai","name":"Kim Cương Bất Hoại","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"bí mật không truyền","hePhai":"Tiểu Tây Thiên","soHuu":["Lý Bạch Đinh"],"blurb":"Kim Cương Bất Hoại là thần thông bí mật không truyền của Tiểu Tây Thiên. Lý Bạch Đinh luyện đến cảnh giới cao và dùng nó đánh bay lão bộc của vị hôn thê.","detail":"Khi bị lão bộc của vị hôn thê ra tay, Lý Bạch Đinh thi triển Kim Cương Bất Hoại, sau lưng hiện kim cương trợn mắt, tỏa bảo huy và đánh bật đối thủ. Mọi người nhận ra đây là bí mật không truyền của Tiểu Tây Thiên, chứng tỏ hắn đã nhận chân truyền và luyện sâu pháp này.","nguon":["@c0289"]},{"id":"than-anh-trong-muoi-dong-thien","name":"Thần ảnh trong mười động thiên","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Nguyệt Thiền tiên tử"],"blurb":"Hiện ra các thần ảnh từ mười Động Thiên để trực tiếp đối kháng cường địch.","detail":"Nguyệt Thiền tiên tử điều động những thần ảnh hiện ra từ mười Động Thiên để đối kháng Thạch Hạo. Các hình thể trong Động Thiên hóa thành hình người giống nàng, cùng tụng niệm và tạo sức trấn áp lên đối thủ.","nguon":["@c0291"]},{"id":"than-thong-hoa-thien","name":"Thần thông Hóa Thiên","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đại thần thông","hePhai":"","soHuu":["Nguyệt Thiền tiên tử"],"blurb":"Đại thần thông có khả năng hóa giải và chuyển hướng sức mạnh công kích của đối phương.","detail":"Nguyệt Thiền tiên tử vận dụng Hóa Thiên để dẫn lực công kích của Thạch Hạo vào hư không hoặc mặt đất. Sức mạnh bị chuyển đi lan truyền tới phương xa, đủ sức khiến một ngọn núi nổ tung thành bột mịn.","nguon":["@c0292"]},{"id":"thap-dai-dong-thien-hop-nhat","name":"Thập đại Động Thiên hợp nhất","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Động Thiên","soHuu":["Thạch Hạo"],"blurb":"Thần thông nối liền mười Động Thiên của Thạch Hạo, hợp thành một vầng thái dương lớn để công kích.","detail":"Khi thi triển, thập đại Động Thiên đồng thời phát sáng và nối liền với nhau, tạo thành vầng thái dương có sức mạnh đủ làm linh thân của Nguyệt Thiền tiên tử chấn động.","nguon":["@c0293"]},{"id":"linh-than-tai-tao-chan-nga","name":"Linh thân tái tạo chân ngã","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông trấn giáo","hePhai":"","soHuu":["Nguyệt Thiền tiên tử"],"blurb":"Thần thông tạo ra một linh thân gần như không khác chân thân, có thể dùng để đánh tráo bản thể trong thời gian ngắn.","detail":"Nguyệt Thiền tiên tử đã tu luyện thần thông này đến mức xuất thần nhập hóa. Linh thân có thể đối phó địch thủ thay chân thân, sau đó hóa thành mưa ánh sáng và trở về Động Thiên của nàng.","nguon":["@c0293"]},{"id":"than-ma-chien-vuc","name":"Thần Ma Chiến Vực","cn":"","loai":"than-thong","loaiLabel":"Thần thông không gian","phamCap":"","hePhai":"","soHuu":[],"blurb":"Một chiến vực cách biệt cuộc giao tranh với thế giới hiện thực, khiến người ngoài không nhìn thấy diễn biến bên trong.","detail":"Không gian này che giấu trận vây công linh thân Nguyệt Thiền tiên tử. Kiếm quang từ chân thân của nàng phá vỡ hư không, khiến Thần Ma Chiến Vực biến mất và những người bên trong trở lại thế giới hiện thực.","nguon":["@c0293"]},{"id":"lua-nhen-an-mon","name":"Lụa nhện ăn mòn","cn":"","loai":"than-thong","loaiLabel":"Thần thông thiên phú","phamCap":"","hePhai":"Hồ Ma Linh","soHuu":["Bích Ma Hắc Đồng Chu"],"blurb":"Thần thông phun ra lụa nhện có khả năng ăn mòn bảo cụ, đồng thời kết thành lưới lớn và xích thần trật tự để trói, trấn áp đối thủ.","detail":"Bích Ma Hắc Đồng Chu dùng những dải lụa có sức ăn mòn để đối phó Thạch Hạo, sau đó đan chúng thành lưới và xích thần trật tự. Thạch Hạo vận dụng cốt văn cơ bản trong Nguyên Thủy Chân Giải hóa thành lửa, thiêu hủy toàn bộ lụa nhện.","nguon":["@c0295"]},{"id":"toc-xanh-sat-thuat","name":"Tóc xanh sát thuật","cn":"","loai":"than-thong","loaiLabel":"Đại sát thuật","phamCap":"","hePhai":"Hồ Ma Linh","soHuu":["Bích Ma Hắc Đồng Chu"],"blurb":"Sát thuật khiến mái tóc xanh tăng vọt, phát sáng và phân thành nhiều nhánh mang phù văn để quấn, công kích đối thủ.","detail":"Trong hình người, Bích Ma Hắc Đồng Chu thi triển sát thuật khiến tóc xanh chia thành hàng chục nhánh quấn lấy cánh tay Thạch Hạo. Các nhánh tóc bị Thạch Hạo dùng một chưởng đánh đứt.","nguon":["@c0295"]},{"id":"bat-diet-kim-than","name":"Bất Diệt Kim Thân","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Thủ đoạn chiến đấu được Thạch Hạo cân nhắc để đối phó cường giả vương hầu như Thạch Tử Đằng.","detail":"Muốn chống lại Thạch Tử Đằng, Thạch Hạo phải khiến Bất Diệt Kim Thân phát huy tiềm lực rất lớn; cách làm này có nguy cơ khiến người tí hon màu đen liên quan đến nó bị tổn hại.","nguon":["@c0297"]},{"id":"dao-hoa-minh-van-canh","name":"Đạo hỏa Minh Văn cảnh","cn":"","loai":"than-thong","loaiLabel":"Thần thông cảnh giới","phamCap":"Minh Văn cảnh","hePhai":"","soHuu":["Văn sĩ trung niên áo xanh ngọc"],"blurb":"Hỏa diễm đặc biệt do phù văn trong cơ thể tu sĩ Minh Văn cảnh kết thành, có sức thiêu đốt và áp chế tu sĩ cảnh giới thấp hơn.","detail":"Văn sĩ trung niên áo xanh ngọc vận dụng đạo hỏa thiêu hòn non bộ thành dung nham và sấy khô suối phun. Khi dùng để công kích Thạch Hạo, hỏa diễm bị mười Động Thiên hấp thu.","nguon":["@c0299"]},{"id":"tran-ky-phong-toa-vien-tu","name":"Trận kỳ phong tỏa viện tử","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":["Văn sĩ trung niên áo xanh ngọc","Bốn kẻ mai phục trong viện"],"blurb":"Trận pháp dùng nhiều trận kỳ để phong tỏa và cô lập một khu vực với bên ngoài.","detail":"Nhóm mai phục bố trí nhiều trận kỳ quanh viện riêng của Thạch Hạo tại khách sạn Hổ Môn. Khi trận kỳ phát sáng, màn khói bao phủ khu vực và ngăn cách viện tử với bên ngoài, tạo thành sát cục phục kích.","nguon":["@c0299"]},{"id":"bao-thuat-loi-dien-cua-thach-hao","name":"Bảo thuật lôi điện của Thạch Hạo","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật","phamCap":"","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Bảo thuật phóng ra những tia chớp lớn để công kích đối thủ và truyền điện qua binh khí.","detail":"Thạch Hạo thi triển những tia chớp vừa thô vừa lớn va chạm với ma đao màu đen. Điện lực chạy dọc thân đao, khiến người cầm đao chịu chấn động mạnh.","nguon":["@c0300"]},{"id":"bao-thuat-mua-sam-cua-vu-toc","name":"Bảo thuật mưa sấm của Vũ tộc","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật","phamCap":"","hePhai":"Vũ tộc","soHuu":["Cao thủ Minh Văn cảnh của Vũ tộc"],"blurb":"Bảo thuật tạo sương mù, mưa lớn và sấm sét để bao phủ, công kích chiến trường.","detail":"Cao thủ Minh Văn cảnh của Vũ tộc dùng sương mù mông lung bao phủ toàn thân, gọi xuống mưa lớn kèm sấm sét đánh vào Thạch Hạo. Đòn đánh không gây thương tổn cho Thạch Hạo sau khi nó tăng cường thực lực.","nguon":["@c0300"]},{"id":"hop-nhat-nguoi-ti-hon-mau-den","name":"Hợp nhất người tí hon màu đen","cn":"","loai":"bi-thuat","loaiLabel":"Thần thông tăng cường","phamCap":"","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Phương thức dung hợp với người tí hon màu đen, giúp Thạch Hạo tăng vọt chiến lực lên cấp Minh Văn cảnh.","detail":"Khi hợp nhất với người tí hon màu đen, toàn thân Thạch Hạo phát ra ánh đen và thực lực tăng mạnh. Trạng thái này giúp nó đạt chiến lực cấp Minh Văn cảnh để đối đầu các cao thủ Vũ tộc.","nguon":["@c0300"]}]};